import Foundation

struct CategoryContent4 {
    static let promptEngineering = CategoryData(
        id: "prompt_engineering", name: "Talking to AI", icon: "text.cursor", colorName: "aiOrange",
        description: "Learn how to ask AI the right questions",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 3,
        unlockRequirement: .completeCategory("generative_ai")
    )
    static let lesson1 = LessonData(id: "pe_l1", title: "Introduction to Prompting", description: "The art of talking to AI", categoryId: "prompt_engineering", questions: [
        Question(id: "pe1_q1", type: .multipleChoice, questionText: "A 'prompt' in AI refers to:", options: ["The text input you provide to guide an AI model's response", "The dataset an AI model was trained on", "The hardware configuration running the model", "The output an AI model generates"], correctAnswer: "The text input you provide to guide an AI model's response", explanation: "A prompt is the instruction or query you give to models like Claude, Gemini, or GPT to shape their output."),
        Question(id: "pe1_q2", type: .trueFalse, questionText: "The same prompt can produce different results on different AI models such as Claude, Gemini, and Llama.", options: ["True", "False"], correctAnswer: "True", explanation: "Each model has different training data, architectures, and fine-tuning, so the same prompt often yields different responses across Claude, Gemini, GPT, Llama, and Mistral."),
        Question(id: "pe1_q3", type: .fillInBlank, questionText: "Prompt __________ is the discipline of crafting effective instructions for large language models.", options: ["engineering", "tuning", "modeling", "processing"], correctAnswer: "engineering", explanation: "Prompt engineering has become a key skill as organizations adopt AI models from Anthropic, Google DeepMind, OpenAI, Meta AI, and others."),
        Question(id: "pe1_q4", type: .scenarioJudgment, questionText: "A user types 'help' into Claude and gets a broad, unfocused response. They blame the AI model. Is the model at fault?", options: ["No, the prompt was too vague to produce a useful answer", "Yes, the model should infer what the user wants", "It depends on the model version"], correctAnswer: "No, the prompt was too vague to produce a useful answer", explanation: "Vague prompts produce vague answers regardless of whether you use Claude, Gemini, GPT, or any other model. Specificity is essential."),
        Question(id: "pe1_q5", type: .multipleChoice, questionText: "Which prompt would produce the best results across models like Claude, Gemini, and GPT?", options: ["Write a 100-word summary of photosynthesis for a 10-year-old audience", "Tell me about plants", "Science stuff", "Something interesting"], correctAnswer: "Write a 100-word summary of photosynthesis for a 10-year-old audience", explanation: "Specific prompts with clear length, topic, and audience details produce better outputs across all major AI models."),
        Question(id: "pe1_q6", type: .multipleChoice, questionText: "What are the three core elements of an effective prompt for any large language model?", options: ["Clarity, specificity, and relevant context", "Brevity, ambiguity, and formality", "Technical jargon, length, and complexity", "Keywords, hashtags, and emojis"], correctAnswer: "Clarity, specificity, and relevant context", explanation: "Whether prompting Claude, Gemini, GPT, Llama, or Mistral, clear instructions with specifics and context consistently produce the best results.")
    ], order: 0, difficulty: .beginner)
    static let lesson2 = LessonData(id: "pe_l2", title: "Prompt Techniques", description: "Advanced prompting strategies", categoryId: "prompt_engineering", questions: [
        Question(id: "pe2_q1", type: .multipleChoice, questionText: "What is 'few-shot prompting' as used with models like Claude and Gemini?", options: ["Providing a few input-output examples within the prompt", "Training the model on a small dataset", "Using brief single-word instructions", "Limiting the model's response length"], correctAnswer: "Providing a few input-output examples within the prompt", explanation: "Few-shot prompting includes examples of desired input-output pairs directly in your prompt, guiding models like Claude, GPT, and Gemini without any retraining."),
        Question(id: "pe2_q2", type: .trueFalse, questionText: "Zero-shot prompting means asking an AI model to perform a task without providing any examples.", options: ["True", "False"], correctAnswer: "True", explanation: "Zero-shot prompting relies entirely on the model's pre-trained knowledge. Models like Claude and GPT-4 perform well zero-shot on many tasks."),
        Question(id: "pe2_q3", type: .matchPairs, questionText: "Match each prompting technique to its description:", matchPairs: [
            MatchPair(term: "Zero-shot", definition: "No examples given"),
            MatchPair(term: "Few-shot", definition: "A few examples provided"),
            MatchPair(term: "Chain-of-thought", definition: "Step-by-step reasoning"),
            MatchPair(term: "Role prompting", definition: "Assign AI a persona")
        ], explanation: "These techniques work across Claude, Gemini, GPT, Llama, and Mistral, though effectiveness varies by model."),
        Question(id: "pe2_q4", type: .fillInBlank, questionText: "__________ prompting, popularized by Google DeepMind research, asks the AI to reason through a problem step by step.", options: ["Chain-of-thought", "Zero-shot", "Random", "Silent"], correctAnswer: "Chain-of-thought", explanation: "Chain-of-thought prompting was shown to dramatically improve reasoning in large language models, and is now a standard technique across Claude, GPT, and Gemini."),
        Question(id: "pe2_q5", type: .multipleChoice, questionText: "When is few-shot prompting most useful across models like Claude, GPT, and Llama?", options: ["When you need the output to follow a very specific format", "When you have no preferences about the response", "When asking simple yes-or-no questions", "When the model already produces the exact format you want"], correctAnswer: "When you need the output to follow a very specific format", explanation: "Examples are most helpful when you need any model to follow a specific pattern, such as a custom JSON schema or a particular writing style."),
        Question(id: "pe2_q6", type: .scenarioJudgment, questionText: "You need an AI model to solve a multi-step logic puzzle. Should you use chain-of-thought prompting?", options: ["Yes, it significantly improves reasoning accuracy", "No, it has no effect on logic tasks", "It depends on the model's size"], correctAnswer: "Yes, it significantly improves reasoning accuracy", explanation: "Chain-of-thought prompting improves performance on reasoning tasks across Claude, Gemini, GPT, and other large language models by encouraging step-by-step analysis.")
    ], order: 1, difficulty: .intermediate)
    static let lesson3 = LessonData(id: "pe_l3", title: "System Prompts & Roles", description: "Setting context for AI", categoryId: "prompt_engineering", questions: [
        Question(id: "pe3_q1", type: .multipleChoice, questionText: "A system prompt, used by APIs from Anthropic, OpenAI, and Google, is:", options: ["A set of instructions that defines the AI's behavior and boundaries", "The user's first conversational message", "The model's internal training objective function", "A log of all previous interactions with the model"], correctAnswer: "A set of instructions that defines the AI's behavior and boundaries", explanation: "System prompts are supported by Claude's API, OpenAI's API, and Google's Gemini API to define role, tone, and constraints before conversation begins."),
        Question(id: "pe3_q2", type: .trueFalse, questionText: "Assigning an AI model a specific role, like 'act as a science tutor,' can improve the quality and relevance of its explanations.", options: ["True", "False"], correctAnswer: "True", explanation: "Role prompting helps models like Claude, Gemini, and GPT adopt an appropriate tone, vocabulary, and depth for the given context."),
        Question(id: "pe3_q3", type: .fillInBlank, questionText: "A __________ prompt defines the AI's role, tone, and constraints before the user interaction begins.", options: ["system", "user", "initial", "training"], correctAnswer: "system", explanation: "System prompts are set by developers using APIs from Anthropic, OpenAI, Google, and others to guide model behavior throughout a conversation."),
        Question(id: "pe3_q4", type: .multipleChoice, questionText: "Which role prompt would best help an AI model explain medical information in plain language?", options: ["You are a friendly doctor explaining a condition to a patient in simple terms", "You are a supercomputer processing health data", "Be yourself and respond naturally", "Respond only in technical medical terminology"], correctAnswer: "You are a friendly doctor explaining a condition to a patient in simple terms", explanation: "This role prompt gives models like Claude or Gemini a specific persona, audience, and communication style to follow."),
        Question(id: "pe3_q5", type: .multipleChoice, questionText: "In production AI applications built on Claude, GPT, or Gemini, system prompts are typically set by:", options: ["The application developers who build the product", "End users during their conversations", "The AI model itself based on context clues", "The cloud infrastructure provider"], correctAnswer: "The application developers who build the product", explanation: "Developers use system prompts in the Anthropic, OpenAI, or Google APIs to control how AI behaves within their specific applications."),
        Question(id: "pe3_q6", type: .scenarioJudgment, questionText: "A children's educational chatbot built on a large language model has no system prompt restrictions or safety guidelines. Is this a concern?", options: ["Yes, this is a serious safety concern", "No, modern AI models are safe by default", "It depends on which AI model is used"], correctAnswer: "Yes, this is a serious safety concern", explanation: "AI chatbots for children need strong system prompts with safety guardrails regardless of the underlying model. Anthropic, OpenAI, and Google all recommend safety-focused system prompts for sensitive applications.")
    ], order: 2, difficulty: .intermediate)
    static let lesson4 = LessonData(id: "pe_l4", title: "Prompt Iteration", description: "Refining prompts for better results", categoryId: "prompt_engineering", questions: [
        Question(id: "pe4_q1", type: .multipleChoice, questionText: "What is prompt iteration in the context of working with AI models?", options: ["Refining your prompt based on the model's responses to improve results", "Submitting the same prompt repeatedly without changes", "Switching between different AI models for each attempt", "Using automated tools to generate random prompts"], correctAnswer: "Refining your prompt based on the model's responses to improve results", explanation: "Prompt iteration means analyzing output from Claude, Gemini, GPT, or any model and adjusting your prompt to get progressively better results."),
        Question(id: "pe4_q2", type: .trueFalse, questionText: "The first prompt you write usually produces the optimal result from an AI model.", options: ["True", "False"], correctAnswer: "False", explanation: "Prompts almost always improve through iteration. Professional prompt engineers at companies like Anthropic and Google routinely test and refine prompts across multiple rounds."),
        Question(id: "pe4_q3", type: .sortOrder, questionText: "Put these prompt iteration steps in the correct order:", options: ["Identify gaps in response", "Write initial prompt", "Refine and re-prompt", "Review AI output"], correctAnswers: ["Write initial prompt", "Review AI output", "Identify gaps in response", "Refine and re-prompt"], explanation: "Effective iteration follows a cycle: write, review, analyze gaps, and refine. This process works the same whether you use Claude, Gemini, GPT, or Llama."),
        Question(id: "pe4_q4", type: .fillInBlank, questionText: "Adding __________ to your prompt, such as word count limits or format requirements, helps any AI model focus its output.", options: ["constraints", "keywords", "formatting", "references"], correctAnswer: "constraints", explanation: "Constraints like word count, output format, tone, or audience help narrow the response from Claude, Gemini, GPT, and other models to what you actually need."),
        Question(id: "pe4_q5", type: .multipleChoice, questionText: "If an AI model's response is too long and unfocused, what should you add to your prompt?", options: ["A specific word or character limit for the response", "More follow-up questions to extend the conversation", "Random filler words to change the context", "Nothing — simply accept whatever the model produces"], correctAnswer: "A specific word or character limit for the response", explanation: "Specifying output length is a simple but effective constraint. Most models including Claude, Gemini, and GPT respect explicit length instructions."),
        Question(id: "pe4_q6", type: .multipleChoice, questionText: "Which parameter, available in APIs from Anthropic, OpenAI, and Google, controls how creative or deterministic an AI model's responses are?", options: ["Temperature", "Token limit", "Top-k filtering", "Batch size"], correctAnswer: "Temperature", explanation: "Temperature controls randomness in output. Higher values produce more creative and varied responses, while lower values yield more focused and deterministic results across Claude, GPT, and Gemini.")
    ], order: 3, difficulty: .intermediate)
    static let lesson5 = LessonData(id: "pe_l5", title: "Common Prompting Mistakes", description: "What to avoid when prompting", categoryId: "prompt_engineering", questions: [
        Question(id: "pe5_q1", type: .multipleChoice, questionText: "What is the most common prompting mistake people make with AI models like Claude, Gemini, and GPT?", options: ["Being too vague in their instructions", "Providing too many specific details", "Including helpful examples in the prompt", "Giving the model relevant background context"], correctAnswer: "Being too vague in their instructions", explanation: "Vague prompts lead to generic, unhelpful responses from any AI model. Specificity is the single biggest factor in prompt quality."),
        Question(id: "pe5_q2", type: .trueFalse, questionText: "Combining multiple unrelated questions in a single prompt is a recommended practice for efficiency.", options: ["True", "False"], correctAnswer: "False", explanation: "Mixing unrelated topics in one prompt confuses models like Claude, Gemini, and GPT. Break requests into separate, focused prompts for better results."),
        Question(id: "pe5_q3", type: .matchPairs, questionText: "Match each prompting mistake with its fix:", matchPairs: [
            MatchPair(term: "Too vague", definition: "Add specific details"),
            MatchPair(term: "No context", definition: "Explain the situation"),
            MatchPair(term: "No format specified", definition: "Request bullet points or JSON"),
            MatchPair(term: "Ambiguous terms", definition: "Define key terminology")
        ], explanation: "These fixes apply universally across Claude, Gemini, GPT, Llama, Mistral, and other large language models."),
        Question(id: "pe5_q4", type: .scenarioJudgment, questionText: "Someone asks Claude: 'Tell me everything about science.' Is this a well-crafted prompt?", options: ["No, it is far too broad for any model to answer effectively", "Yes, it allows the model to showcase its full knowledge", "It depends on the model's context window size"], correctAnswer: "No, it is far too broad for any model to answer effectively", explanation: "This prompt is too broad for Claude, Gemini, GPT, or any model. Narrowing the topic, audience, and scope dramatically improves output quality."),
        Question(id: "pe5_q5", type: .fillInBlank, questionText: "A prompt that assumes the AI model already has __________ context about your specific situation often leads to poor results.", options: ["missing", "sufficient", "complete", "prior"], correctAnswer: "missing", explanation: "AI models do not know your specific situation. Always provide relevant context whether you are using Claude, Gemini, GPT, or any other model."),
        Question(id: "pe5_q6", type: .multipleChoice, questionText: "Why should you avoid double negatives when prompting AI models?", options: ["They create ambiguity about what you actually want", "They make the prompt too short for the model", "They consume more tokens than necessary", "They are flagged as errors by all AI models"], correctAnswer: "They create ambiguity about what you actually want", explanation: "Double negatives like 'don't not include' confuse language models. Clear, positive statements work better across Claude, Gemini, GPT, and all other models.")
    ], order: 4, difficulty: .intermediate)
    static let lesson6 = LessonData(id: "pe_l6", title: "Real-World Prompting", description: "Practical applications", categoryId: "prompt_engineering", questions: [
        Question(id: "pe6_q1", type: .multipleChoice, questionText: "For summarizing a long article using Claude, Gemini, or GPT, the best prompting approach is:", options: ["Paste the article and specify summary length, audience, and key points to cover", "Simply type 'summarize' with no further context", "Ask the AI to search for and find the article itself", "Copy a single sentence and ask the model to expand it"], correctAnswer: "Paste the article and specify summary length, audience, and key points to cover", explanation: "Providing the full text with clear instructions on length, focus, and audience produces the best summaries across all major AI models."),
        Question(id: "pe6_q2", type: .trueFalse, questionText: "You can prompt AI models like Claude, Gemini, and GPT to output structured data formats such as JSON, CSV, or XML.", options: ["True", "False"], correctAnswer: "True", explanation: "Specifying output format in your prompt allows models from Anthropic, Google, OpenAI, and Meta to produce structured, machine-readable data."),
        Question(id: "pe6_q3", type: .scenarioJudgment, questionText: "A developer asks an AI coding assistant to write code but does not specify the programming language, framework, or version. Will the result be reliable?", options: ["No, always specify language, framework, and requirements", "Yes, AI coding assistants always choose the best option", "It depends on whether they use GitHub Copilot or another tool"], correctAnswer: "No, always specify language, framework, and requirements", explanation: "Whether using Claude, GitHub Copilot, Gemini Code Assist, or another AI coding tool, always specify language, framework, and requirements for reliable code generation."),
        Question(id: "pe6_q4", type: .multipleChoice, questionText: "When using any AI model for creative writing, which prompt element helps most?", options: ["Specifying tone, target audience, and writing style", "Using as few words as possible in the prompt", "Simply asking for 'something good and interesting'", "Copying a prompt template without customizing it"], correctAnswer: "Specifying tone, target audience, and writing style", explanation: "Clear creative direction on tone, audience, and style significantly improves output from Claude, Gemini, GPT, and other models used for creative tasks."),
        Question(id: "pe6_q5", type: .fillInBlank, questionText: "Using AI models like Claude or Gemini to review and improve your own writing is called AI-assisted __________.", options: ["editing", "indexing", "transcribing", "archiving"], correctAnswer: "editing", explanation: "AI-assisted editing uses models from Anthropic, Google, OpenAI, and others to proofread, improve clarity, and suggest better phrasing."),
        Question(id: "pe6_q6", type: .multipleChoice, questionText: "What is the benefit of building a personal library of effective prompts?", options: ["You can reuse and adapt proven prompts for similar tasks across different models", "The prompts become proprietary intellectual property of the AI company", "Saved prompts make the AI model run faster over time", "Reusing prompts reduces your internet bandwidth usage"], correctAnswer: "You can reuse and adapt proven prompts for similar tasks across different models", explanation: "A prompt library saves time and ensures consistent quality. Many effective prompts transfer well between Claude, Gemini, GPT, and other models with minor adjustments.")
    ], order: 5, difficulty: .advanced)
}
